INSERT INTO drug_interaction_rules (rule_code, ingredient_a_code, ingredient_b_code, pair_key, severity, action_type, is_overridable, title_vi, clinical_effect_vi, mechanism_vi, recommendation_vi, monitoring_guidance_vi, route_scope, evidence_level, source_name, source_reference, source_url, rule_set_version, review_status, is_active) VALUES ('DDI-DEMO-001', 'ING004203', 'ING002976', 'ING002976:ING004203', 'HIGH', 'CONTRAINDICATED', FALSE, 'Chống chỉ định sildenafil với nitroglycerin', 'Có thể gây tụt huyết áp nghiêm trọng, choáng hoặc ngất.', 'Hai thuốc cùng làm tăng tín hiệu nitric oxide–cGMP và cộng hợp tác dụng giãn mạch.', 'Không sử dụng đồng thời; phải loại bỏ một thuốc và chuyển đánh giá cho bác sĩ/dược sĩ.', 'Theo dõi huyết áp và triệu chứng tim mạch nếu đã dùng nhầm.', 'SYSTEMIC_ONLY', 'OFFICIAL_LABEL', 'DailyMed/FDA drug label', 'Contraindications; Drug Interactions', 'https://dailymed.nlm.nih.gov/dailymed/search.cfm?query=sildenafil', 'DDI-DEMO-2026.06', 'EVIDENCE_CHECKED_FOR_DEMO', TRUE) ON CONFLICT (pair_key, rule_set_version) DO UPDATE SET severity = EXCLUDED.severity, action_type = EXCLUDED.action_type, is_overridable = EXCLUDED.is_overridable, title_vi = EXCLUDED.title_vi, clinical_effect_vi = EXCLUDED.clinical_effect_vi, mechanism_vi = EXCLUDED.mechanism_vi, recommendation_vi = EXCLUDED.recommendation_vi, monitoring_guidance_vi = EXCLUDED.monitoring_guidance_vi, source_url = EXCLUDED.source_url, review_status = EXCLUDED.review_status, is_active = EXCLUDED.is_active;
INSERT INTO drug_interaction_rules (rule_code, ingredient_a_code, ingredient_b_code, pair_key, severity, action_type, is_overridable, title_vi, clinical_effect_vi, mechanism_vi, recommendation_vi, monitoring_guidance_vi, route_scope, evidence_level, source_name, source_reference, source_url, rule_set_version, review_status, is_active) VALUES ('DDI-DEMO-002', 'ING002572', 'ING002848', 'ING002572:ING002848', 'HIGH', 'CONTRAINDICATED', FALSE, 'Clarithromycin làm tăng độc tính simvastatin', 'Tăng nguy cơ bệnh cơ và tiêu cơ vân.', 'Clarithromycin ức chế mạnh CYP3A4, làm tăng nồng độ simvastatin.', 'Không phối hợp; chọn kháng sinh hoặc statin khác theo chỉ định chuyên môn.', 'Theo dõi đau cơ, yếu cơ và CK nếu đã phơi nhiễm.', 'SYSTEMIC_ONLY', 'OFFICIAL_LABEL', 'DailyMed/FDA drug label', 'Contraindications; Drug Interactions', 'https://dailymed.nlm.nih.gov/dailymed/search.cfm?query=clarithromycin', 'DDI-DEMO-2026.06', 'EVIDENCE_CHECKED_FOR_DEMO', TRUE) ON CONFLICT (pair_key, rule_set_version) DO UPDATE SET severity = EXCLUDED.severity, action_type = EXCLUDED.action_type, is_overridable = EXCLUDED.is_overridable, title_vi = EXCLUDED.title_vi, clinical_effect_vi = EXCLUDED.clinical_effect_vi, mechanism_vi = EXCLUDED.mechanism_vi, recommendation_vi = EXCLUDED.recommendation_vi, monitoring_guidance_vi = EXCLUDED.monitoring_guidance_vi, source_url = EXCLUDED.source_url, review_status = EXCLUDED.review_status, is_active = EXCLUDED.is_active;
INSERT INTO drug_interaction_rules (rule_code, ingredient_a_code, ingredient_b_code, pair_key, severity, action_type, is_overridable, title_vi, clinical_effect_vi, mechanism_vi, recommendation_vi, monitoring_guidance_vi, route_scope, evidence_level, source_name, source_reference, source_url, rule_set_version, review_status, is_active) VALUES ('DDI-DEMO-003', 'ING002612', 'ING002848', 'ING002612:ING002848', 'HIGH', 'AVOID_COMBINATION', FALSE, 'Erythromycin làm tăng độc tính simvastatin', 'Tăng nguy cơ bệnh cơ và tiêu cơ vân.', 'Erythromycin ức chế CYP3A4, làm giảm chuyển hóa simvastatin.', 'Tránh phối hợp; tạm ngừng simvastatin hoặc chọn thuốc thay thế theo bác sĩ.', 'Theo dõi triệu chứng cơ và chức năng thận nếu đã dùng chung.', 'SYSTEMIC_ONLY', 'OFFICIAL_LABEL', 'DailyMed/FDA drug label', 'Drug Interactions / Warnings and Precautions', 'https://dailymed.nlm.nih.gov/dailymed/search.cfm?query=simvastatin', 'DDI-DEMO-2026.06', 'EVIDENCE_CHECKED_FOR_DEMO', TRUE) ON CONFLICT (pair_key, rule_set_version) DO UPDATE SET severity = EXCLUDED.severity, action_type = EXCLUDED.action_type, is_overridable = EXCLUDED.is_overridable, title_vi = EXCLUDED.title_vi, clinical_effect_vi = EXCLUDED.clinical_effect_vi, mechanism_vi = EXCLUDED.mechanism_vi, recommendation_vi = EXCLUDED.recommendation_vi, monitoring_guidance_vi = EXCLUDED.monitoring_guidance_vi, source_url = EXCLUDED.source_url, review_status = EXCLUDED.review_status, is_active = EXCLUDED.is_active;
INSERT INTO drug_interaction_rules (rule_code, ingredient_a_code, ingredient_b_code, pair_key, severity, action_type, is_overridable, title_vi, clinical_effect_vi, mechanism_vi, recommendation_vi, monitoring_guidance_vi, route_scope, evidence_level, source_name, source_reference, source_url, rule_set_version, review_status, is_active) VALUES ('DDI-DEMO-004', 'ING002572', 'ING003605', 'ING002572:ING003605', 'HIGH', 'AVOID_COMBINATION', FALSE, 'Nguy cơ ngộ độc colchicine nghiêm trọng', 'Có thể gây ức chế tủy, độc tính đa cơ quan và tử vong, đặc biệt khi suy gan hoặc suy thận.', 'Clarithromycin ức chế CYP3A4 và P-gp, làm tăng mạnh phơi nhiễm colchicine.', 'Tránh phối hợp; chuyển bác sĩ/dược sĩ để thay kháng sinh hoặc điều chỉnh chuyên môn.', 'Theo dõi tiêu chảy, nôn, yếu cơ và bất thường huyết học nếu đã dùng chung.', 'SYSTEMIC_ONLY', 'OFFICIAL_LABEL', 'DailyMed/FDA drug label', 'Drug Interactions / Warnings and Precautions', 'https://dailymed.nlm.nih.gov/dailymed/search.cfm?query=clarithromycin', 'DDI-DEMO-2026.06', 'EVIDENCE_CHECKED_FOR_DEMO', TRUE) ON CONFLICT (pair_key, rule_set_version) DO UPDATE SET severity = EXCLUDED.severity, action_type = EXCLUDED.action_type, is_overridable = EXCLUDED.is_overridable, title_vi = EXCLUDED.title_vi, clinical_effect_vi = EXCLUDED.clinical_effect_vi, mechanism_vi = EXCLUDED.mechanism_vi, recommendation_vi = EXCLUDED.recommendation_vi, monitoring_guidance_vi = EXCLUDED.monitoring_guidance_vi, source_url = EXCLUDED.source_url, review_status = EXCLUDED.review_status, is_active = EXCLUDED.is_active;
INSERT INTO drug_interaction_rules (rule_code, ingredient_a_code, ingredient_b_code, pair_key, severity, action_type, is_overridable, title_vi, clinical_effect_vi, mechanism_vi, recommendation_vi, monitoring_guidance_vi, route_scope, evidence_level, source_name, source_reference, source_url, rule_set_version, review_status, is_active) VALUES ('DDI-DEMO-005', 'ING002545', 'ING003605', 'ING002545:ING003605', 'HIGH', 'ADJUST_DOSE_OR_MONITOR', TRUE, 'Fluconazole có thể làm tăng độc tính colchicine', 'Tăng nguy cơ độc tính tiêu hóa, cơ và huyết học.', 'Fluconazole ức chế CYP3A4 ở mức độ vừa, có thể làm giảm chuyển hóa colchicine.', 'Tránh nếu có thể; nếu bắt buộc phải dùng, cần bác sĩ điều chỉnh liều và theo dõi.', 'Theo dõi triệu chứng độc tính colchicine và chức năng gan thận.', 'SYSTEMIC_ONLY', 'OFFICIAL_LABEL', 'DailyMed/FDA drug label', 'Drug Interactions / Warnings and Precautions', 'https://dailymed.nlm.nih.gov/dailymed/search.cfm?query=colchicine', 'DDI-DEMO-2026.06', 'EVIDENCE_CHECKED_FOR_DEMO', TRUE) ON CONFLICT (pair_key, rule_set_version) DO UPDATE SET severity = EXCLUDED.severity, action_type = EXCLUDED.action_type, is_overridable = EXCLUDED.is_overridable, title_vi = EXCLUDED.title_vi, clinical_effect_vi = EXCLUDED.clinical_effect_vi, mechanism_vi = EXCLUDED.mechanism_vi, recommendation_vi = EXCLUDED.recommendation_vi, monitoring_guidance_vi = EXCLUDED.monitoring_guidance_vi, source_url = EXCLUDED.source_url, review_status = EXCLUDED.review_status, is_active = EXCLUDED.is_active;
INSERT INTO drug_interaction_rules (rule_code, ingredient_a_code, ingredient_b_code, pair_key, severity, action_type, is_overridable, title_vi, clinical_effect_vi, mechanism_vi, recommendation_vi, monitoring_guidance_vi, route_scope, evidence_level, source_name, source_reference, source_url, rule_set_version, review_status, is_active) VALUES ('DDI-DEMO-006', 'ING000419', 'ING002876', 'ING000419:ING002876', 'HIGH', 'CONTRAINDICATED', FALSE, 'Nguy cơ tăng kali máu nặng', 'Có thể gây yếu cơ, rối loạn nhịp tim hoặc ngừng tim.', 'Spironolactone giữ kali; bổ sung potassium chloride làm tăng thêm kali huyết.', 'Không phối hợp thường quy; chỉ dùng khi có chỉ định và giám sát xét nghiệm chặt chẽ.', 'Theo dõi kali huyết, creatinine và điện tâm đồ.', 'SYSTEMIC_ONLY', 'OFFICIAL_LABEL', 'DailyMed/FDA drug label', 'Drug Interactions / Warnings and Precautions', 'https://dailymed.nlm.nih.gov/dailymed/search.cfm?query=spironolactone', 'DDI-DEMO-2026.06', 'EVIDENCE_CHECKED_FOR_DEMO', TRUE) ON CONFLICT (pair_key, rule_set_version) DO UPDATE SET severity = EXCLUDED.severity, action_type = EXCLUDED.action_type, is_overridable = EXCLUDED.is_overridable, title_vi = EXCLUDED.title_vi, clinical_effect_vi = EXCLUDED.clinical_effect_vi, mechanism_vi = EXCLUDED.mechanism_vi, recommendation_vi = EXCLUDED.recommendation_vi, monitoring_guidance_vi = EXCLUDED.monitoring_guidance_vi, source_url = EXCLUDED.source_url, review_status = EXCLUDED.review_status, is_active = EXCLUDED.is_active;
INSERT INTO drug_interaction_rules (rule_code, ingredient_a_code, ingredient_b_code, pair_key, severity, action_type, is_overridable, title_vi, clinical_effect_vi, mechanism_vi, recommendation_vi, monitoring_guidance_vi, route_scope, evidence_level, source_name, source_reference, source_url, rule_set_version, review_status, is_active) VALUES ('DDI-DEMO-007', 'ING002586', 'ING003011', 'ING002586:ING003011', 'HIGH', 'AVOID_COMBINATION', TRUE, 'Nguy cơ hội chứng serotonin', 'Có thể gây kích động, tăng thân nhiệt, tăng phản xạ, run và rối loạn thần kinh tự chủ.', 'Linezolid ức chế monoamine oxidase có hồi phục; sertraline tăng dẫn truyền serotonin.', 'Tránh phối hợp nếu không có chỉ định khẩn cấp; cần bác sĩ đánh giá ngừng hoặc thay thuốc.', 'Theo dõi sát dấu hiệu hội chứng serotonin trong và sau khi phối hợp.', 'SYSTEMIC_ONLY', 'FDA_SAFETY_COMMUNICATION', 'FDA Drug Safety Communication', 'Linezolid and serotonergic psychiatric medications', 'https://www.fda.gov/drugs/drug-safety-and-availability/fda-drug-safety-communication-updated-information-about-drug-interaction-between-linezolid-zyvox-and', 'DDI-DEMO-2026.06', 'EVIDENCE_CHECKED_FOR_DEMO', TRUE) ON CONFLICT (pair_key, rule_set_version) DO UPDATE SET severity = EXCLUDED.severity, action_type = EXCLUDED.action_type, is_overridable = EXCLUDED.is_overridable, title_vi = EXCLUDED.title_vi, clinical_effect_vi = EXCLUDED.clinical_effect_vi, mechanism_vi = EXCLUDED.mechanism_vi, recommendation_vi = EXCLUDED.recommendation_vi, monitoring_guidance_vi = EXCLUDED.monitoring_guidance_vi, source_url = EXCLUDED.source_url, review_status = EXCLUDED.review_status, is_active = EXCLUDED.is_active;
INSERT INTO drug_interaction_rules (rule_code, ingredient_a_code, ingredient_b_code, pair_key, severity, action_type, is_overridable, title_vi, clinical_effect_vi, mechanism_vi, recommendation_vi, monitoring_guidance_vi, route_scope, evidence_level, source_name, source_reference, source_url, rule_set_version, review_status, is_active) VALUES ('DDI-DEMO-008', 'ING002586', 'ING003832', 'ING002586:ING003832', 'HIGH', 'AVOID_COMBINATION', TRUE, 'Linezolid và tramadol làm tăng serotonin', 'Tăng nguy cơ hội chứng serotonin và co giật.', 'Linezolid ức chế monoamine oxidase; tramadol có hoạt tính serotonergic.', 'Tránh phối hợp; chọn thuốc giảm đau hoặc kháng sinh khác theo chỉ định.', 'Theo dõi trạng thái tinh thần, thân nhiệt, phản xạ và co giật.', 'SYSTEMIC_ONLY', 'OFFICIAL_LABEL', 'DailyMed/FDA drug label', 'Drug Interactions / Warnings and Precautions', 'https://dailymed.nlm.nih.gov/dailymed/search.cfm?query=linezolid', 'DDI-DEMO-2026.06', 'EVIDENCE_CHECKED_FOR_DEMO', TRUE) ON CONFLICT (pair_key, rule_set_version) DO UPDATE SET severity = EXCLUDED.severity, action_type = EXCLUDED.action_type, is_overridable = EXCLUDED.is_overridable, title_vi = EXCLUDED.title_vi, clinical_effect_vi = EXCLUDED.clinical_effect_vi, mechanism_vi = EXCLUDED.mechanism_vi, recommendation_vi = EXCLUDED.recommendation_vi, monitoring_guidance_vi = EXCLUDED.monitoring_guidance_vi, source_url = EXCLUDED.source_url, review_status = EXCLUDED.review_status, is_active = EXCLUDED.is_active;
INSERT INTO drug_interaction_rules (rule_code, ingredient_a_code, ingredient_b_code, pair_key, severity, action_type, is_overridable, title_vi, clinical_effect_vi, mechanism_vi, recommendation_vi, monitoring_guidance_vi, route_scope, evidence_level, source_name, source_reference, source_url, rule_set_version, review_status, is_active) VALUES ('DDI-DEMO-009', 'ING003832', 'ING003011', 'ING003011:ING003832', 'HIGH', 'AVOID_COMBINATION', TRUE, 'Tramadol và sertraline làm tăng nguy cơ serotonin', 'Có thể gây hội chứng serotonin và tăng nguy cơ co giật.', 'Cả hai thuốc đều tăng hoạt tính serotonin; tramadol còn làm giảm ngưỡng co giật.', 'Tránh nếu có lựa chọn khác; nếu bắt buộc, cần chỉ định và giám sát chuyên môn.', 'Theo dõi kích động, run, tăng thân nhiệt, tăng phản xạ và co giật.', 'SYSTEMIC_ONLY', 'OFFICIAL_LABEL', 'DailyMed/FDA drug label', 'Drug Interactions / Warnings and Precautions', 'https://dailymed.nlm.nih.gov/dailymed/search.cfm?query=tramadol', 'DDI-DEMO-2026.06', 'EVIDENCE_CHECKED_FOR_DEMO', TRUE) ON CONFLICT (pair_key, rule_set_version) DO UPDATE SET severity = EXCLUDED.severity, action_type = EXCLUDED.action_type, is_overridable = EXCLUDED.is_overridable, title_vi = EXCLUDED.title_vi, clinical_effect_vi = EXCLUDED.clinical_effect_vi, mechanism_vi = EXCLUDED.mechanism_vi, recommendation_vi = EXCLUDED.recommendation_vi, monitoring_guidance_vi = EXCLUDED.monitoring_guidance_vi, source_url = EXCLUDED.source_url, review_status = EXCLUDED.review_status, is_active = EXCLUDED.is_active;
INSERT INTO drug_interaction_rules (rule_code, ingredient_a_code, ingredient_b_code, pair_key, severity, action_type, is_overridable, title_vi, clinical_effect_vi, mechanism_vi, recommendation_vi, monitoring_guidance_vi, route_scope, evidence_level, source_name, source_reference, source_url, rule_set_version, review_status, is_active) VALUES ('DDI-DEMO-010', 'ING002594', 'ING002855', 'ING002594:ING002855', 'HIGH', 'AVOID_COMBINATION', FALSE, 'Nguy cơ kéo dài QT và xoắn đỉnh', 'Tăng nguy cơ loạn nhịp thất nghiêm trọng.', 'Cả moxifloxacin và amiodarone đều có thể kéo dài khoảng QT.', 'Tránh phối hợp; chọn kháng sinh không kéo dài QT nếu phù hợp.', 'Kiểm tra ECG, kali và magiê nếu không thể tránh.', 'SYSTEMIC_ONLY', 'OFFICIAL_LABEL', 'DailyMed/FDA drug label', 'Drug Interactions / Warnings and Precautions', 'https://dailymed.nlm.nih.gov/dailymed/search.cfm?query=moxifloxacin', 'DDI-DEMO-2026.06', 'EVIDENCE_CHECKED_FOR_DEMO', TRUE) ON CONFLICT (pair_key, rule_set_version) DO UPDATE SET severity = EXCLUDED.severity, action_type = EXCLUDED.action_type, is_overridable = EXCLUDED.is_overridable, title_vi = EXCLUDED.title_vi, clinical_effect_vi = EXCLUDED.clinical_effect_vi, mechanism_vi = EXCLUDED.mechanism_vi, recommendation_vi = EXCLUDED.recommendation_vi, monitoring_guidance_vi = EXCLUDED.monitoring_guidance_vi, source_url = EXCLUDED.source_url, review_status = EXCLUDED.review_status, is_active = EXCLUDED.is_active;
INSERT INTO drug_interaction_rules (rule_code, ingredient_a_code, ingredient_b_code, pair_key, severity, action_type, is_overridable, title_vi, clinical_effect_vi, mechanism_vi, recommendation_vi, monitoring_guidance_vi, route_scope, evidence_level, source_name, source_reference, source_url, rule_set_version, review_status, is_active) VALUES ('DDI-DEMO-011', 'ING002549', 'ING002855', 'ING002549:ING002855', 'HIGH', 'AVOID_COMBINATION', TRUE, 'Levofloxacin và amiodarone kéo dài QT', 'Tăng nguy cơ xoắn đỉnh và loạn nhịp thất.', 'Tác dụng kéo dài QT cộng hợp.', 'Tránh nếu có lựa chọn khác; cần ECG và đánh giá yếu tố nguy cơ khi bắt buộc.', 'Theo dõi ECG, kali, magiê và triệu chứng hồi hộp/ngất.', 'SYSTEMIC_ONLY', 'OFFICIAL_LABEL', 'DailyMed/FDA drug label', 'Drug Interactions / Warnings and Precautions', 'https://dailymed.nlm.nih.gov/dailymed/search.cfm?query=levofloxacin', 'DDI-DEMO-2026.06', 'EVIDENCE_CHECKED_FOR_DEMO', TRUE) ON CONFLICT (pair_key, rule_set_version) DO UPDATE SET severity = EXCLUDED.severity, action_type = EXCLUDED.action_type, is_overridable = EXCLUDED.is_overridable, title_vi = EXCLUDED.title_vi, clinical_effect_vi = EXCLUDED.clinical_effect_vi, mechanism_vi = EXCLUDED.mechanism_vi, recommendation_vi = EXCLUDED.recommendation_vi, monitoring_guidance_vi = EXCLUDED.monitoring_guidance_vi, source_url = EXCLUDED.source_url, review_status = EXCLUDED.review_status, is_active = EXCLUDED.is_active;
INSERT INTO drug_interaction_rules (rule_code, ingredient_a_code, ingredient_b_code, pair_key, severity, action_type, is_overridable, title_vi, clinical_effect_vi, mechanism_vi, recommendation_vi, monitoring_guidance_vi, route_scope, evidence_level, source_name, source_reference, source_url, rule_set_version, review_status, is_active) VALUES ('DDI-DEMO-012', 'ING003282', 'ING002855', 'ING002855:ING003282', 'HIGH', 'AVOID_COMBINATION', TRUE, 'Ondansetron và amiodarone kéo dài QT', 'Tăng nguy cơ rối loạn nhịp thất.', 'Hai thuốc cộng hợp tác dụng kéo dài tái cực tim.', 'Tránh phối hợp hoặc sử dụng dưới giám sát ECG theo chỉ định chuyên môn.', 'Theo dõi ECG và điện giải.', 'SYSTEMIC_ONLY', 'OFFICIAL_LABEL', 'DailyMed/FDA drug label', 'Drug Interactions / Warnings and Precautions', 'https://dailymed.nlm.nih.gov/dailymed/search.cfm?query=ondansetron', 'DDI-DEMO-2026.06', 'EVIDENCE_CHECKED_FOR_DEMO', TRUE) ON CONFLICT (pair_key, rule_set_version) DO UPDATE SET severity = EXCLUDED.severity, action_type = EXCLUDED.action_type, is_overridable = EXCLUDED.is_overridable, title_vi = EXCLUDED.title_vi, clinical_effect_vi = EXCLUDED.clinical_effect_vi, mechanism_vi = EXCLUDED.mechanism_vi, recommendation_vi = EXCLUDED.recommendation_vi, monitoring_guidance_vi = EXCLUDED.monitoring_guidance_vi, source_url = EXCLUDED.source_url, review_status = EXCLUDED.review_status, is_active = EXCLUDED.is_active;
INSERT INTO drug_interaction_rules (rule_code, ingredient_a_code, ingredient_b_code, pair_key, severity, action_type, is_overridable, title_vi, clinical_effect_vi, mechanism_vi, recommendation_vi, monitoring_guidance_vi, route_scope, evidence_level, source_name, source_reference, source_url, rule_set_version, review_status, is_active) VALUES ('DDI-DEMO-013', 'ING002589', 'ING002553', 'ING002553:ING002589', 'HIGH', 'AVOID_COMBINATION', TRUE, 'Nguy cơ kéo dài QT khi phối hợp hydroxychloroquine và azithromycin', 'Tăng nguy cơ loạn nhịp tim nghiêm trọng.', 'Cả hai thuốc có khả năng kéo dài QT và tác dụng có thể cộng hợp.', 'Tránh phối hợp ngoài môi trường có giám sát; cần bác sĩ đánh giá lợi ích–nguy cơ.', 'Theo dõi ECG, kali, magiê và triệu chứng ngất/hồi hộp.', 'SYSTEMIC_ONLY', 'FDA_SAFETY_COMMUNICATION', 'FDA Drug Safety Communication', 'Cardiac rhythm risk with hydroxychloroquine/chloroquine, including with azithromycin', 'https://www.fda.gov/drugs/drug-safety-and-availability/fda-cautions-against-use-hydroxychloroquine-or-chloroquine-covid-19-outside-hospital-setting-or', 'DDI-DEMO-2026.06', 'EVIDENCE_CHECKED_FOR_DEMO', TRUE) ON CONFLICT (pair_key, rule_set_version) DO UPDATE SET severity = EXCLUDED.severity, action_type = EXCLUDED.action_type, is_overridable = EXCLUDED.is_overridable, title_vi = EXCLUDED.title_vi, clinical_effect_vi = EXCLUDED.clinical_effect_vi, mechanism_vi = EXCLUDED.mechanism_vi, recommendation_vi = EXCLUDED.recommendation_vi, monitoring_guidance_vi = EXCLUDED.monitoring_guidance_vi, source_url = EXCLUDED.source_url, review_status = EXCLUDED.review_status, is_active = EXCLUDED.is_active;
INSERT INTO drug_interaction_rules (rule_code, ingredient_a_code, ingredient_b_code, pair_key, severity, action_type, is_overridable, title_vi, clinical_effect_vi, mechanism_vi, recommendation_vi, monitoring_guidance_vi, route_scope, evidence_level, source_name, source_reference, source_url, rule_set_version, review_status, is_active) VALUES ('DDI-DEMO-014', 'ING002589', 'ING003282', 'ING002589:ING003282', 'HIGH', 'AVOID_COMBINATION', TRUE, 'Hydroxychloroquine và ondansetron kéo dài QT', 'Tăng nguy cơ loạn nhịp thất, đặc biệt khi có yếu tố nguy cơ tim mạch.', 'Tác dụng kéo dài QT cộng hợp.', 'Tránh nếu có thể; cần giám sát ECG và điện giải khi phối hợp.', 'Theo dõi QTc, kali và magiê.', 'SYSTEMIC_ONLY', 'OFFICIAL_LABEL', 'DailyMed/FDA drug label', 'Drug Interactions / Warnings and Precautions', 'https://dailymed.nlm.nih.gov/dailymed/search.cfm?query=hydroxychloroquine', 'DDI-DEMO-2026.06', 'EVIDENCE_CHECKED_FOR_DEMO', TRUE) ON CONFLICT (pair_key, rule_set_version) DO UPDATE SET severity = EXCLUDED.severity, action_type = EXCLUDED.action_type, is_overridable = EXCLUDED.is_overridable, title_vi = EXCLUDED.title_vi, clinical_effect_vi = EXCLUDED.clinical_effect_vi, mechanism_vi = EXCLUDED.mechanism_vi, recommendation_vi = EXCLUDED.recommendation_vi, monitoring_guidance_vi = EXCLUDED.monitoring_guidance_vi, source_url = EXCLUDED.source_url, review_status = EXCLUDED.review_status, is_active = EXCLUDED.is_active;
INSERT INTO drug_interaction_rules (rule_code, ingredient_a_code, ingredient_b_code, pair_key, severity, action_type, is_overridable, title_vi, clinical_effect_vi, mechanism_vi, recommendation_vi, monitoring_guidance_vi, route_scope, evidence_level, source_name, source_reference, source_url, rule_set_version, review_status, is_active) VALUES ('DDI-DEMO-015', 'ING003259', 'ING002797', 'ING002797:ING003259', 'HIGH', 'AVOID_COMBINATION', TRUE, 'Omeprazole làm giảm hoạt hóa clopidogrel', 'Có thể làm giảm tác dụng chống kết tập tiểu cầu của clopidogrel.', 'Omeprazole ức chế CYP2C19, enzyme tham gia chuyển clopidogrel thành chất có hoạt tính.', 'Tránh phối hợp; chọn PPI khác phù hợp theo chỉ định chuyên môn.', 'Theo dõi hiệu quả kháng tiểu cầu và biến cố tim mạch theo bác sĩ.', 'SYSTEMIC_ONLY', 'REGULATORY_GUIDANCE', 'NHS Specialist Pharmacy Service / product labeling', 'Using clopidogrel with PPIs', 'https://www.sps.nhs.uk/articles/using-clopidogrel-with-proton-pump-inhibitors-ppis/', 'DDI-DEMO-2026.06', 'EVIDENCE_CHECKED_FOR_DEMO', TRUE) ON CONFLICT (pair_key, rule_set_version) DO UPDATE SET severity = EXCLUDED.severity, action_type = EXCLUDED.action_type, is_overridable = EXCLUDED.is_overridable, title_vi = EXCLUDED.title_vi, clinical_effect_vi = EXCLUDED.clinical_effect_vi, mechanism_vi = EXCLUDED.mechanism_vi, recommendation_vi = EXCLUDED.recommendation_vi, monitoring_guidance_vi = EXCLUDED.monitoring_guidance_vi, source_url = EXCLUDED.source_url, review_status = EXCLUDED.review_status, is_active = EXCLUDED.is_active;
INSERT INTO drug_interaction_rules (rule_code, ingredient_a_code, ingredient_b_code, pair_key, severity, action_type, is_overridable, title_vi, clinical_effect_vi, mechanism_vi, recommendation_vi, monitoring_guidance_vi, route_scope, evidence_level, source_name, source_reference, source_url, rule_set_version, review_status, is_active) VALUES ('DDI-DEMO-016', 'ING003775', 'ING002565', 'ING002565:ING003775', 'HIGH', 'AVOID_COMBINATION', TRUE, 'Methotrexate và trimethoprim tăng độc tính huyết học', 'Tăng nguy cơ ức chế tủy, tổn thương niêm mạc, độc gan hoặc độc thận.', 'Tác dụng kháng folate cộng hợp và giảm thải trừ methotrexate.', 'Tránh tự phối hợp; cần bác sĩ/dược sĩ đánh giá liều, chức năng thận và lựa chọn thay thế.', 'Theo dõi công thức máu, chức năng gan, thận và dấu hiệu loét miệng/nhiễm trùng.', 'SYSTEMIC_ONLY', 'REGULATORY_GUIDANCE', 'NHS Specialist Pharmacy Service / product labeling', 'Managing interactions with methotrexate', 'https://www.sps.nhs.uk/articles/managing-interactions-with-methotrexate/', 'DDI-DEMO-2026.06', 'EVIDENCE_CHECKED_FOR_DEMO', TRUE) ON CONFLICT (pair_key, rule_set_version) DO UPDATE SET severity = EXCLUDED.severity, action_type = EXCLUDED.action_type, is_overridable = EXCLUDED.is_overridable, title_vi = EXCLUDED.title_vi, clinical_effect_vi = EXCLUDED.clinical_effect_vi, mechanism_vi = EXCLUDED.mechanism_vi, recommendation_vi = EXCLUDED.recommendation_vi, monitoring_guidance_vi = EXCLUDED.monitoring_guidance_vi, source_url = EXCLUDED.source_url, review_status = EXCLUDED.review_status, is_active = EXCLUDED.is_active;
