INSERT INTO drug_interaction_rules (rule_code, ingredient_a_code, ingredient_b_code, pair_key, severity, action_type, is_overridable, title_vi, clinical_effect_vi, mechanism_vi, recommendation_vi, monitoring_guidance_vi, route_scope, evidence_level, source_name, source_reference, source_url, rule_set_version, review_status, is_active) VALUES ('DDI-DEMO-020', 'ING003775', 'ING002897', 'ING002897:ING003775', 'HIGH', 'AVOID_COMBINATION', TRUE, 'Aspirin có thể làm tăng độc tính methotrexate', 'Tăng nguy cơ ức chế tủy, tổn thương niêm mạc, độc gan hoặc độc thận.', 'Salicylate có thể làm giảm thải trừ và tăng phơi nhiễm methotrexate.', 'Tránh tự phối hợp; cần bác sĩ/dược sĩ đánh giá liều, chức năng thận và lựa chọn thay thế.', 'Theo dõi công thức máu, chức năng gan, thận và dấu hiệu loét miệng/nhiễm trùng.', 'SYSTEMIC_ONLY', 'REGULATORY_GUIDANCE', 'NHS Specialist Pharmacy Service / product labeling', 'Managing interactions with methotrexate', 'https://www.sps.nhs.uk/articles/managing-interactions-with-methotrexate/', 'DDI-DEMO-2026.06', 'EVIDENCE_CHECKED_FOR_DEMO', TRUE) ON CONFLICT (pair_key, rule_set_version) DO UPDATE SET severity = EXCLUDED.severity, action_type = EXCLUDED.action_type, is_overridable = EXCLUDED.is_overridable, title_vi = EXCLUDED.title_vi, clinical_effect_vi = EXCLUDED.clinical_effect_vi, mechanism_vi = EXCLUDED.mechanism_vi, recommendation_vi = EXCLUDED.recommendation_vi, monitoring_guidance_vi = EXCLUDED.monitoring_guidance_vi, source_url = EXCLUDED.source_url, review_status = EXCLUDED.review_status, is_active = EXCLUDED.is_active;
INSERT INTO drug_interaction_rules (rule_code, ingredient_a_code, ingredient_b_code, pair_key, severity, action_type, is_overridable, title_vi, clinical_effect_vi, mechanism_vi, recommendation_vi, monitoring_guidance_vi, route_scope, evidence_level, source_name, source_reference, source_url, rule_set_version, review_status, is_active) VALUES ('DDI-DEMO-021', 'ING002926', 'ING002897', 'ING002897:ING002926', 'HIGH', 'AVOID_COMBINATION', TRUE, 'Warfarin và aspirin làm tăng nguy cơ chảy máu', 'Tăng nguy cơ xuất huyết tiêu hóa, nội sọ hoặc các chảy máu nghiêm trọng.', 'Tác dụng chống đông của warfarin cộng hợp với ức chế tiểu cầu và tổn thương niêm mạc do aspirin.', 'Chỉ phối hợp khi có chỉ định rõ và kế hoạch theo dõi; tránh tự sử dụng.', 'Theo dõi dấu hiệu chảy máu, hemoglobin và INR; với enoxaparin theo dõi thêm chức năng thận.', 'SYSTEMIC_ONLY', 'OFFICIAL_LABEL', 'DailyMed/FDA drug label', 'Drug Interactions / Warnings and Precautions', 'https://dailymed.nlm.nih.gov/dailymed/search.cfm?query=warfarin', 'DDI-DEMO-2026.06', 'EVIDENCE_CHECKED_FOR_DEMO', TRUE) ON CONFLICT (pair_key, rule_set_version) DO UPDATE SET severity = EXCLUDED.severity, action_type = EXCLUDED.action_type, is_overridable = EXCLUDED.is_overridable, title_vi = EXCLUDED.title_vi, clinical_effect_vi = EXCLUDED.clinical_effect_vi, mechanism_vi = EXCLUDED.mechanism_vi, recommendation_vi = EXCLUDED.recommendation_vi, monitoring_guidance_vi = EXCLUDED.monitoring_guidance_vi, source_url = EXCLUDED.source_url, review_status = EXCLUDED.review_status, is_active = EXCLUDED.is_active;
INSERT INTO drug_interaction_rules (rule_code, ingredient_a_code, ingredient_b_code, pair_key, severity, action_type, is_overridable, title_vi, clinical_effect_vi, mechanism_vi, recommendation_vi, monitoring_guidance_vi, route_scope, evidence_level, source_name, source_reference, source_url, rule_set_version, review_status, is_active) VALUES ('DDI-DEMO-022', 'ING002926', 'ING002983', 'ING002926:ING002983', 'HIGH', 'AVOID_COMBINATION', TRUE, 'Warfarin và ibuprofen làm tăng nguy cơ chảy máu', 'Tăng nguy cơ xuất huyết, đặc biệt xuất huyết tiêu hóa.', 'NSAID ức chế tiểu cầu và gây tổn thương niêm mạc tiêu hóa trong khi warfarin chống đông.', 'Chỉ phối hợp khi có chỉ định rõ và kế hoạch theo dõi; tránh tự sử dụng.', 'Theo dõi dấu hiệu chảy máu, hemoglobin và INR; với enoxaparin theo dõi thêm chức năng thận.', 'SYSTEMIC_ONLY', 'OFFICIAL_LABEL', 'DailyMed/FDA drug label', 'Drug Interactions / Warnings and Precautions', 'https://dailymed.nlm.nih.gov/dailymed/search.cfm?query=warfarin', 'DDI-DEMO-2026.06', 'EVIDENCE_CHECKED_FOR_DEMO', TRUE) ON CONFLICT (pair_key, rule_set_version) DO UPDATE SET severity = EXCLUDED.severity, action_type = EXCLUDED.action_type, is_overridable = EXCLUDED.is_overridable, title_vi = EXCLUDED.title_vi, clinical_effect_vi = EXCLUDED.clinical_effect_vi, mechanism_vi = EXCLUDED.mechanism_vi, recommendation_vi = EXCLUDED.recommendation_vi, monitoring_guidance_vi = EXCLUDED.monitoring_guidance_vi, source_url = EXCLUDED.source_url, review_status = EXCLUDED.review_status, is_active = EXCLUDED.is_active;
