INSERT INTO drug_interaction_rules (rule_code, ingredient_a_code, ingredient_b_code, pair_key, severity, action_type, is_overridable, title_vi, clinical_effect_vi, mechanism_vi, recommendation_vi, monitoring_guidance_vi, route_scope, evidence_level, source_name, source_reference, source_url, rule_set_version, review_status, is_active) VALUES ('DDI-DEMO-026', 'ING002926', 'ING002878', 'ING002878:ING002926', 'HIGH', 'ADJUST_DOSE_OR_MONITOR', TRUE, 'Warfarin và enoxaparin làm tăng nguy cơ chảy máu', 'Nguy cơ chảy máu tăng; phối hợp đôi khi được dùng có chủ đích trong giai đoạn chuyển tiếp.', 'Hai thuốc chống đông tác động trên các bước khác nhau của quá trình đông máu.', 'Chỉ phối hợp khi có chỉ định rõ và kế hoạch theo dõi; tránh tự sử dụng.', 'Theo dõi dấu hiệu chảy máu, hemoglobin và INR; với enoxaparin theo dõi thêm chức năng thận.', 'SYSTEMIC_ONLY', 'OFFICIAL_LABEL', 'DailyMed/FDA drug label', 'Drug Interactions / Warnings and Precautions', 'https://dailymed.nlm.nih.gov/dailymed/search.cfm?query=warfarin', 'DDI-DEMO-2026.06', 'EVIDENCE_CHECKED_FOR_DEMO', TRUE) ON CONFLICT (pair_key, rule_set_version) DO UPDATE SET severity = EXCLUDED.severity, action_type = EXCLUDED.action_type, is_overridable = EXCLUDED.is_overridable, title_vi = EXCLUDED.title_vi, clinical_effect_vi = EXCLUDED.clinical_effect_vi, mechanism_vi = EXCLUDED.mechanism_vi, recommendation_vi = EXCLUDED.recommendation_vi, monitoring_guidance_vi = EXCLUDED.monitoring_guidance_vi, source_url = EXCLUDED.source_url, review_status = EXCLUDED.review_status, is_active = EXCLUDED.is_active;
