INSERT INTO drug_interaction_rules (rule_code, ingredient_a_code, ingredient_b_code, pair_key, severity, action_type, is_overridable, title_vi, clinical_effect_vi, mechanism_vi, recommendation_vi, monitoring_guidance_vi, route_scope, evidence_level, source_name, source_reference, source_url, rule_set_version, review_status, is_active) VALUES ('DDI-DEMO-037', 'ING002926', 'ING002550', 'ING002550:ING002926', 'LOW', 'MONITOR', TRUE, 'Amoxicillin có thể làm thay đổi INR', 'Có thể làm thay đổi INR hoặc tăng nguy cơ chảy máu ở một số bệnh nhân.', 'Kháng sinh có thể làm thay đổi hệ vi khuẩn đường ruột và đáp ứng vitamin K.', 'Có thể dùng khi cần nhưng nên thông báo cho bác sĩ/dược sĩ và không tự kéo dài.', 'Theo dõi INR và dấu hiệu chảy máu khi bắt đầu, ngừng hoặc dùng kéo dài.', 'SYSTEMIC_ONLY', 'OFFICIAL_LABEL', 'DailyMed/FDA drug label', 'Drug Interactions / Warnings and Precautions', 'https://dailymed.nlm.nih.gov/dailymed/search.cfm?query=warfarin', 'DDI-DEMO-2026.06', 'EVIDENCE_CHECKED_FOR_DEMO', TRUE) ON CONFLICT (pair_key, rule_set_version) DO UPDATE SET severity = EXCLUDED.severity, action_type = EXCLUDED.action_type, is_overridable = EXCLUDED.is_overridable, title_vi = EXCLUDED.title_vi, clinical_effect_vi = EXCLUDED.clinical_effect_vi, mechanism_vi = EXCLUDED.mechanism_vi, recommendation_vi = EXCLUDED.recommendation_vi, monitoring_guidance_vi = EXCLUDED.monitoring_guidance_vi, source_url = EXCLUDED.source_url, review_status = EXCLUDED.review_status, is_active = EXCLUDED.is_active;
