INSERT INTO drug_interaction_rules (rule_code, ingredient_a_code, ingredient_b_code, pair_key, severity, action_type, is_overridable, title_vi, clinical_effect_vi, mechanism_vi, recommendation_vi, monitoring_guidance_vi, route_scope, evidence_level, source_name, source_reference, source_url, rule_set_version, review_status, is_active) VALUES ('DDI-DEMO-039', 'ING002926', 'ING003259', 'ING002926:ING003259', 'LOW', 'MONITOR', TRUE, 'Omeprazole có thể ảnh hưởng nhẹ đến warfarin', 'Có thể làm thay đổi INR hoặc tăng nguy cơ chảy máu ở một số bệnh nhân.', 'Có thể làm tăng phơi nhiễm một đồng phân warfarin ở một số người.', 'Có thể dùng khi cần nhưng nên thông báo cho bác sĩ/dược sĩ và không tự kéo dài.', 'Theo dõi INR và dấu hiệu chảy máu khi bắt đầu, ngừng hoặc dùng kéo dài.', 'SYSTEMIC_ONLY', 'OFFICIAL_LABEL', 'DailyMed/FDA drug label', 'Drug Interactions / Warnings and Precautions', 'https://dailymed.nlm.nih.gov/dailymed/search.cfm?query=warfarin', 'DDI-DEMO-2026.06', 'EVIDENCE_CHECKED_FOR_DEMO', TRUE) ON CONFLICT (pair_key, rule_set_version) DO UPDATE SET severity = EXCLUDED.severity, action_type = EXCLUDED.action_type, is_overridable = EXCLUDED.is_overridable, title_vi = EXCLUDED.title_vi, clinical_effect_vi = EXCLUDED.clinical_effect_vi, mechanism_vi = EXCLUDED.mechanism_vi, recommendation_vi = EXCLUDED.recommendation_vi, monitoring_guidance_vi = EXCLUDED.monitoring_guidance_vi, source_url = EXCLUDED.source_url, review_status = EXCLUDED.review_status, is_active = EXCLUDED.is_active;
INSERT INTO drug_interaction_rules (rule_code, ingredient_a_code, ingredient_b_code, pair_key, severity, action_type, is_overridable, title_vi, clinical_effect_vi, mechanism_vi, recommendation_vi, monitoring_guidance_vi, route_scope, evidence_level, source_name, source_reference, source_url, rule_set_version, review_status, is_active) VALUES ('DDI-DEMO-040', 'ING002897', 'ING002983', 'ING002897:ING002983', 'MEDIUM', 'ADJUST_DOSE_OR_MONITOR', TRUE, 'Ibuprofen làm tăng nguy cơ chảy máu và có thể cản trở tác dụng aspirin', 'Tăng nguy cơ xuất huyết tiêu hóa; dùng gần thời điểm có thể làm giảm tác dụng chống tiểu cầu của aspirin liều thấp.', 'Hai NSAID cộng hợp độc tính tiêu hóa; ibuprofen có thể cạnh tranh tại COX-1 tiểu cầu.', 'Tránh dùng thường xuyên cùng nhau; bác sĩ/dược sĩ cần hướng dẫn thời điểm hoặc lựa chọn thay thế.', 'Theo dõi đau thượng vị, phân đen và dấu hiệu chảy máu.', 'SYSTEMIC_ONLY', 'OFFICIAL_LABEL', 'DailyMed/FDA drug label', 'Drug Interactions / Warnings and Precautions', 'https://dailymed.nlm.nih.gov/dailymed/search.cfm?query=aspirin', 'DDI-DEMO-2026.06', 'EVIDENCE_CHECKED_FOR_DEMO', TRUE) ON CONFLICT (pair_key, rule_set_version) DO UPDATE SET severity = EXCLUDED.severity, action_type = EXCLUDED.action_type, is_overridable = EXCLUDED.is_overridable, title_vi = EXCLUDED.title_vi, clinical_effect_vi = EXCLUDED.clinical_effect_vi, mechanism_vi = EXCLUDED.mechanism_vi, recommendation_vi = EXCLUDED.recommendation_vi, monitoring_guidance_vi = EXCLUDED.monitoring_guidance_vi, source_url = EXCLUDED.source_url, review_status = EXCLUDED.review_status, is_active = EXCLUDED.is_active;
INSERT INTO drug_interaction_rules (rule_code, ingredient_a_code, ingredient_b_code, pair_key, severity, action_type, is_overridable, title_vi, clinical_effect_vi, mechanism_vi, recommendation_vi, monitoring_guidance_vi, route_scope, evidence_level, source_name, source_reference, source_url, rule_set_version, review_status, is_active) VALUES ('DDI-DEMO-041', 'ING002897', 'ING003587', 'ING002897:ING003587', 'MEDIUM', 'AVOID_COMBINATION', TRUE, 'Aspirin và naproxen làm tăng nguy cơ chảy máu', 'Tăng nguy cơ loét và xuất huyết tiêu hóa.', 'Tác dụng NSAID và ức chế tiểu cầu cộng hợp.', 'Tránh phối hợp thường quy; chọn thuốc giảm đau khác nếu phù hợp.', 'Theo dõi dấu hiệu xuất huyết tiêu hóa.', 'SYSTEMIC_ONLY', 'OFFICIAL_LABEL', 'DailyMed/FDA drug label', 'Drug Interactions / Warnings and Precautions', 'https://dailymed.nlm.nih.gov/dailymed/search.cfm?query=aspirin', 'DDI-DEMO-2026.06', 'EVIDENCE_CHECKED_FOR_DEMO', TRUE) ON CONFLICT (pair_key, rule_set_version) DO UPDATE SET severity = EXCLUDED.severity, action_type = EXCLUDED.action_type, is_overridable = EXCLUDED.is_overridable, title_vi = EXCLUDED.title_vi, clinical_effect_vi = EXCLUDED.clinical_effect_vi, mechanism_vi = EXCLUDED.mechanism_vi, recommendation_vi = EXCLUDED.recommendation_vi, monitoring_guidance_vi = EXCLUDED.monitoring_guidance_vi, source_url = EXCLUDED.source_url, review_status = EXCLUDED.review_status, is_active = EXCLUDED.is_active;
INSERT INTO drug_interaction_rules (rule_code, ingredient_a_code, ingredient_b_code, pair_key, severity, action_type, is_overridable, title_vi, clinical_effect_vi, mechanism_vi, recommendation_vi, monitoring_guidance_vi, route_scope, evidence_level, source_name, source_reference, source_url, rule_set_version, review_status, is_active) VALUES ('DDI-DEMO-042', 'ING002797', 'ING002897', 'ING002797:ING002897', 'MEDIUM', 'ADJUST_DOSE_OR_MONITOR', TRUE, 'Phối hợp clopidogrel và aspirin làm tăng chảy máu', 'Tăng nguy cơ chảy máu; phối hợp có thể là điều trị có chủ đích trong một số bệnh tim mạch.', 'Ức chế tiểu cầu qua hai cơ chế khác nhau.', 'Chỉ sử dụng khi có chỉ định; không tự thêm aspirin.', 'Theo dõi xuất huyết, hemoglobin và thời gian điều trị kép.', 'SYSTEMIC_ONLY', 'OFFICIAL_LABEL', 'DailyMed/FDA drug label', 'Drug Interactions / Warnings and Precautions', 'https://dailymed.nlm.nih.gov/dailymed/search.cfm?query=clopidogrel', 'DDI-DEMO-2026.06', 'EVIDENCE_CHECKED_FOR_DEMO', TRUE) ON CONFLICT (pair_key, rule_set_version) DO UPDATE SET severity = EXCLUDED.severity, action_type = EXCLUDED.action_type, is_overridable = EXCLUDED.is_overridable, title_vi = EXCLUDED.title_vi, clinical_effect_vi = EXCLUDED.clinical_effect_vi, mechanism_vi = EXCLUDED.mechanism_vi, recommendation_vi = EXCLUDED.recommendation_vi, monitoring_guidance_vi = EXCLUDED.monitoring_guidance_vi, source_url = EXCLUDED.source_url, review_status = EXCLUDED.review_status, is_active = EXCLUDED.is_active;
INSERT INTO drug_interaction_rules (rule_code, ingredient_a_code, ingredient_b_code, pair_key, severity, action_type, is_overridable, title_vi, clinical_effect_vi, mechanism_vi, recommendation_vi, monitoring_guidance_vi, route_scope, evidence_level, source_name, source_reference, source_url, rule_set_version, review_status, is_active) VALUES ('DDI-DEMO-043', 'ING002797', 'ING002983', 'ING002797:ING002983', 'HIGH', 'AVOID_COMBINATION', TRUE, 'Clopidogrel và ibuprofen làm tăng nguy cơ chảy máu', 'Tăng nguy cơ xuất huyết tiêu hóa.', 'Ức chế tiểu cầu cộng với tổn thương niêm mạc và tác dụng tiểu cầu của NSAID.', 'Tránh nếu có thể; chọn thuốc giảm đau khác theo bác sĩ/dược sĩ.', 'Theo dõi phân đen, nôn máu, bầm tím và hemoglobin.', 'SYSTEMIC_ONLY', 'OFFICIAL_LABEL', 'DailyMed/FDA drug label', 'Drug Interactions / Warnings and Precautions', 'https://dailymed.nlm.nih.gov/dailymed/search.cfm?query=clopidogrel', 'DDI-DEMO-2026.06', 'EVIDENCE_CHECKED_FOR_DEMO', TRUE) ON CONFLICT (pair_key, rule_set_version) DO UPDATE SET severity = EXCLUDED.severity, action_type = EXCLUDED.action_type, is_overridable = EXCLUDED.is_overridable, title_vi = EXCLUDED.title_vi, clinical_effect_vi = EXCLUDED.clinical_effect_vi, mechanism_vi = EXCLUDED.mechanism_vi, recommendation_vi = EXCLUDED.recommendation_vi, monitoring_guidance_vi = EXCLUDED.monitoring_guidance_vi, source_url = EXCLUDED.source_url, review_status = EXCLUDED.review_status, is_active = EXCLUDED.is_active;
INSERT INTO drug_interaction_rules (rule_code, ingredient_a_code, ingredient_b_code, pair_key, severity, action_type, is_overridable, title_vi, clinical_effect_vi, mechanism_vi, recommendation_vi, monitoring_guidance_vi, route_scope, evidence_level, source_name, source_reference, source_url, rule_set_version, review_status, is_active) VALUES ('DDI-DEMO-044', 'ING002878', 'ING002897', 'ING002878:ING002897', 'HIGH', 'ADJUST_DOSE_OR_MONITOR', TRUE, 'Enoxaparin và aspirin làm tăng nguy cơ chảy máu', 'Tăng nguy cơ xuất huyết, dù phối hợp có thể được chỉ định trong hội chứng vành cấp.', 'Chống đông và chống kết tập tiểu cầu cộng hợp.', 'Chỉ phối hợp khi có chỉ định và liều rõ ràng.', 'Theo dõi chảy máu, tiểu cầu, hemoglobin và chức năng thận.', 'SYSTEMIC_ONLY', 'OFFICIAL_LABEL', 'DailyMed/FDA drug label', 'Drug Interactions / Warnings and Precautions', 'https://dailymed.nlm.nih.gov/dailymed/search.cfm?query=enoxaparin', 'DDI-DEMO-2026.06', 'EVIDENCE_CHECKED_FOR_DEMO', TRUE) ON CONFLICT (pair_key, rule_set_version) DO UPDATE SET severity = EXCLUDED.severity, action_type = EXCLUDED.action_type, is_overridable = EXCLUDED.is_overridable, title_vi = EXCLUDED.title_vi, clinical_effect_vi = EXCLUDED.clinical_effect_vi, mechanism_vi = EXCLUDED.mechanism_vi, recommendation_vi = EXCLUDED.recommendation_vi, monitoring_guidance_vi = EXCLUDED.monitoring_guidance_vi, source_url = EXCLUDED.source_url, review_status = EXCLUDED.review_status, is_active = EXCLUDED.is_active;
INSERT INTO drug_interaction_rules (rule_code, ingredient_a_code, ingredient_b_code, pair_key, severity, action_type, is_overridable, title_vi, clinical_effect_vi, mechanism_vi, recommendation_vi, monitoring_guidance_vi, route_scope, evidence_level, source_name, source_reference, source_url, rule_set_version, review_status, is_active) VALUES ('DDI-DEMO-045', 'ING002878', 'ING002983', 'ING002878:ING002983', 'HIGH', 'AVOID_COMBINATION', TRUE, 'Enoxaparin và ibuprofen làm tăng nguy cơ chảy máu', 'Tăng nguy cơ xuất huyết tiêu hóa và chảy máu khác.', 'Tác dụng chống đông cộng hợp với NSAID.', 'Tránh nếu có thể; ưu tiên thuốc giảm đau khác theo hướng dẫn chuyên môn.', 'Theo dõi chảy máu, hemoglobin và chức năng thận.', 'SYSTEMIC_ONLY', 'OFFICIAL_LABEL', 'DailyMed/FDA drug label', 'Drug Interactions / Warnings and Precautions', 'https://dailymed.nlm.nih.gov/dailymed/search.cfm?query=enoxaparin', 'DDI-DEMO-2026.06', 'EVIDENCE_CHECKED_FOR_DEMO', TRUE) ON CONFLICT (pair_key, rule_set_version) DO UPDATE SET severity = EXCLUDED.severity, action_type = EXCLUDED.action_type, is_overridable = EXCLUDED.is_overridable, title_vi = EXCLUDED.title_vi, clinical_effect_vi = EXCLUDED.clinical_effect_vi, mechanism_vi = EXCLUDED.mechanism_vi, recommendation_vi = EXCLUDED.recommendation_vi, monitoring_guidance_vi = EXCLUDED.monitoring_guidance_vi, source_url = EXCLUDED.source_url, review_status = EXCLUDED.review_status, is_active = EXCLUDED.is_active;
