INSERT INTO drug_interaction_rules (rule_code, ingredient_a_code, ingredient_b_code, pair_key, severity, action_type, is_overridable, title_vi, clinical_effect_vi, mechanism_vi, recommendation_vi, monitoring_guidance_vi, route_scope, evidence_level, source_name, source_reference, source_url, rule_set_version, review_status, is_active) VALUES ('DDI-DEMO-084', 'ING004205', 'ING003085', 'ING003085:ING004205', 'MEDIUM', 'SEPARATE_ADMINISTRATION', TRUE, 'Calcium carbonate làm giảm hấp thu levothyroxine', 'Giảm hiệu quả điều trị suy giáp và có thể làm tăng TSH.', 'Tạo phức hoặc hấp phụ levothyroxine trong đường tiêu hóa.', 'Uống cách nhau ít nhất 4 giờ và duy trì cách dùng ổn định.', 'Theo dõi TSH/FT4 sau thay đổi lịch dùng hoặc bắt đầu/ngừng thuốc tương tác.', 'SYSTEMIC_ONLY', 'OFFICIAL_LABEL', 'DailyMed/FDA drug label', 'Drug Interactions / Warnings and Precautions', 'https://dailymed.nlm.nih.gov/dailymed/search.cfm?query=levothyroxine', 'DDI-DEMO-2026.06', 'EVIDENCE_CHECKED_FOR_DEMO', TRUE) ON CONFLICT (pair_key, rule_set_version) DO UPDATE SET severity = EXCLUDED.severity, action_type = EXCLUDED.action_type, is_overridable = EXCLUDED.is_overridable, title_vi = EXCLUDED.title_vi, clinical_effect_vi = EXCLUDED.clinical_effect_vi, mechanism_vi = EXCLUDED.mechanism_vi, recommendation_vi = EXCLUDED.recommendation_vi, monitoring_guidance_vi = EXCLUDED.monitoring_guidance_vi, source_url = EXCLUDED.source_url, review_status = EXCLUDED.review_status, is_active = EXCLUDED.is_active;
